import React, { useState, useEffect } from 'react';
import { useTable } from 'react-table';

const columns = [
  { Header: 'ID', accessor: 'id' },
  { Header: 'Location', accessor: 'location' },
  { Header: 'Material ID', accessor: 'materialid' },
  { Header: 'Quantity', accessor: 'quantity' },
  { Header: 'Date', accessor: 'date' },
  {
    Header: 'Actions',
    accessor: 'actions', // This accessor is just for the header, not used for data
    Cell: ({ row }) => (
      <div>
        <button onClick={() => handleEdit(row)}>Edit</button>
        <button onClick={() => handleDelete(row)}>Delete</button>
      </div>
    ),
  },
];
const handleEdit = (row) => {
  // Assuming you're using a modal or a separate page for editing
  const editedPurchase = { /* Extract the edited values from the modal or form */ };

  // Make a PUT request to update the purchase
  fetch(`http://localhost:8081/PurchasesAPI/${row.original.id}`, {
    method: 'PUT',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(editedPurchase),
  })
    .then(response => {
      if (!response.ok) {
        throw new Error('Failed to update the purchase.');
      }
      // Optionally, you can update the local state to reflect the changes immediately
    })
    .catch(error => {
      console.error('Error updating the purchase:', error);
      // Handle the error, show a notification, or display a user-friendly message
    });
};

const handleDelete = (row) => {
  // Display a confirmation dialog to confirm the deletion
  const isConfirmed = window.confirm('Are you sure you want to delete this purchase?');

  if (isConfirmed) {
    // Make a DELETE request to delete the purchase
    fetch(`http://localhost:8081/PurchasesAPI/${row.original.id}`, {
      method: 'DELETE',
    })
      .then(response => {
        if (!response.ok) {
          throw new Error('Failed to delete the purchase.');
        }
        // Optionally, you can remove the deleted purchase from the local state immediately
      })
      .catch(error => {
        console.error('Error deleting the purchase:', error);
        // Handle the error, show a notification, or display a user-friendly message
      });
  }
};


function PurchaseFunc() {
  const [purchases, setPurchases] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setIsLoading(true);
    setError(null);

    try {
      const response = await fetch('http://localhost:8081/PurchasesAPI');
      if (!response.ok) {
        throw new Error('Failed to fetch data');
      }
      const data = await response.json();
      setPurchases(data);
    } catch (error) {
      setError(error);
    } finally {
      setIsLoading(false);
    }
  };

  const tableInstance = useTable({ columns, data: purchases });

  const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow } = tableInstance;

  

  return (
    <div>
      <h1>My Purchases</h1>
  
      {/* Add form for adding purchases */}
      <form>
        <label>
          Location:
          <input type="text" name="location" />
        </label>
        <label>
          Material ID:
          <input type="text" name="materialid" />
        </label>
        <label>
          Quantity:
          <input type="number" name="quantity" />
        </label>
        <button type="submit">Add Purchase</button>
      </form>

      {isLoading ? (
        <div>Loading...</div>
      ) : error ? (
        <div>Error: {error.message}</div>
      ) : (
        <table {...getTableProps()} style={{ border: '1px solid black' }}>
          <thead>
            {headerGroups.map(headerGroup => (
              <tr {...headerGroup.getHeaderGroupProps()} style={{ background: 'lightgray' }}>
                {headerGroup.headers.map(column => (
                  <th
                    {...column.getHeaderProps()}
                    style={{ padding: '5px', border: '1px solid black' }}
                  >
                    {column.render('Header')}
                  </th>
                ))}
              </tr>
            ))}
          </thead>
          <tbody {...getTableBodyProps()}>
            {rows.map(row => {
              prepareRow(row);
              return (
                <tr {...row.getRowProps()}>
                  {row.cells.map(cell => (
                    <td
                      {...cell.getCellProps()}
                      style={{ padding: '5px', border: '1px solid black' }}
                    >
                      {cell.render('Cell')}
                    </td>
                  ))}
                </tr>
              );
            })}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default PurchaseFunc;
